INSERT INTO genres (deck, id, name) VALUES ('The comic publishing industry of the Philippines.', '40616', 'Pilipino Komiks');
INSERT INTO genres (deck, id, name) VALUES ('The generic term for Multiverses or What If...? type scenarios. An Alternate Universe usually features pre-established characters living in different situations from those of the main continuity universe.', '40617', 'Alternate Reality');
INSERT INTO genres (deck, id, name) VALUES ('Also known as gridiron football, the sport is more a variant of rugby football than association football but because of the word football colloquially meaning different sports depending on the culture, it is usually called American football. This distinction is regularly played up as a quirk of America but Canadian football is essentially the same sport with a few minor rule differences and Japan uses the same football/soccer terminology as America.', '40993', 'American Football');
INSERT INTO genres (deck, id, name) VALUES ('Although the term Green Lantern has come to be associated with the entire Green Lantern Corps, this page is for the major superhero mantle of Green Lantern which predates the concept of the Corps and has been a headlining DC franchise since the Golden Age.', '41148', 'Green Lantern');
INSERT INTO genres (deck, id, name) VALUES ('The Fastball Special is a maneuver in which Colossus launches Wolverine at an enemy, claws-first.', '41709', 'Fastball Special');
INSERT INTO genres (deck, id, name) VALUES ('The unique publishing industry of Hong Kong that began during the era of British Hong Kong but has continued independently since the reintegration into Mainland China.', '42077', 'Hong Kong Manhua');
INSERT INTO genres (deck, id, name) VALUES ('Although there are many comics about specific martial arts (which are represented by their own pages), this page covers all of the more single-use or obscure martial arts as well as the popular genre of stories where fighters are a complete mixture of various martial arts.', '42287', 'Martial Arts');
INSERT INTO genres (deck, id, name) VALUES ('Created in 1954 amidst controversy subsequent to the publication of Dr. Fredric Wertham''s book "Seduction of the Innocent", publishers established the code to curb potential governmental regulation. The fall of the Code is most often attributed to Alan Moore and his work on the Swamp Thing in the 80''s.', '42382', 'Comics Code Authority');
INSERT INTO genres (deck, id, name) VALUES ('Comics and graphic novels have given us many famous and notable advertisements through the years. Who can forget the Charles Atlas ads, the X-Ray Specks, Sea Monkeys, or the mysterious Grab Bag?', '43049', 'Advertising in Comics');
INSERT INTO genres (deck, id, name) VALUES ('Article covering the role of women in comics throughout the ages.', '43357', 'Women in Comics');
INSERT INTO genres (deck, id, name) VALUES ('The largest English-language comic industry outside of the United States.', '43598', 'British Comics');
INSERT INTO genres (deck, id, name) VALUES ('This page is using the term ''manga'' in the colloquial sense to refer to the comic publishing industry of Japan, for further clarification read below.', '43603', 'Manga');
INSERT INTO genres (deck, id, name) VALUES ('The comic industry of Turkey, which has quite a large output compared to many other Muslim territories.', '43647', 'Çizgi Roman');
INSERT INTO genres (deck, id, name) VALUES ('The event or realization that changed a character''s life forever and made them into the person they are today. In superhero comics especially, one of the most iconic aspects of major characters is their origin stories. Below are listed the most prominent examples in the medium.', '43721', 'Origin Stories in Comics');
INSERT INTO genres (deck, id, name) VALUES ('Covers that pay homage to, or parody, existing covers or artwork from the same or different medias.', '43734', 'Homage Covers');
INSERT INTO genres (deck, id, name) VALUES ('Free Comic Book Day is the one day a year where participating comic book shops in America and around the world give away comic books free to anyone who comes into the store.', '43738', 'Free Comic Book Day');
INSERT INTO genres (deck, id, name) VALUES ('A term that was created by Gail Simone. Women in Refrigerators (WiR) refers to comic book women who have been depowered, raped, murdered and/or had their lives ruined specifically in order to fuel the stories of men.', '43763', 'Women in Refrigerators');
INSERT INTO genres (deck, id, name) VALUES ('Specifically the sport of swimming in all its variations (including diving), rather than passively engaging in it.', '44158', 'Swimming');
INSERT INTO genres (deck, id, name) VALUES ('Were you enjoying a comic book series until suddenly it changes for the worse, and it is no longer as good as it once was and is in serious decline? Well then, that series has "jumped the shark."', '44257', 'Jumping the Shark');
