INSERT INTO genres (deck, id, name) VALUES ('The comic industry of Greece.', '44586', 'Elliniká Kómiks');
INSERT INTO genres (deck, id, name) VALUES ('A literary term often utilized in theater to describe the imaginary barrier between the actors and audience, separating real world and fantasy. Breaking the fourth wall is observed sometimes in literature, where a character directly addresses the reader.', '44795', 'Fourth Wall');
INSERT INTO genres (deck, id, name) VALUES ('One of the core artistic aspects of comic books and generally the one that is most concentrated on a few individuals who can letter thousands of highly notable comics by a wide variety of writers and artists.', '45747', 'Lettering in Comics');
INSERT INTO genres (deck, id, name) VALUES ('This concept would cover toys, such as dolls and accessories, based on comics.', '45784', 'Comic Based Toys');
INSERT INTO genres (deck, id, name) VALUES ('This page displays examples of the pull-out posters or the Centerfolds in comic books.', '45787', 'Centerfold');
INSERT INTO genres (deck, id, name) VALUES ('Although not exactly the same as standard newcomer awards in manga, Ikiman was the prize used by Ikki to encourage one-shots to be submitted where the winner would be published in the magazine and could lead to serializations.', '45806', 'Ikiman');
INSERT INTO genres (deck, id, name) VALUES ('''Elseworlds'', or ''Imaginary Stories'' are tales where a fresh concept or idea is tried on an existing character or storyline. This often leads to a new and fresh take on existing characters. ''Elseworlds'' is also when the narrator give characters new story lines, and concepts.', '46699', 'Elseworlds');
INSERT INTO genres (deck, id, name) VALUES ('Comic industry of the Netherlands specifically.', '46747', 'Stripverhaal');
INSERT INTO genres (deck, id, name) VALUES ('Specifically the comic industry of France which is often conflated with all French-language comics but here is restricted.', '47520', 'Bande Dessinée en France');
INSERT INTO genres (deck, id, name) VALUES ('The Top Cow Pilot Season is an annual initiative that began in 2007 to determine the next ongoing series from the publisher.', '47795', 'Top Cow Pilot Season');
INSERT INTO genres (deck, id, name) VALUES ('M-Tech was a Marvel imprint that spun-off from the X-men arc, "Rage Against the Machine." The titles focused on hi-tech heroes and consisted of three unrelated books: Warlock, X-51, and Deathlok.', '49473', 'M-Tech');
