INSERT INTO genres (deck, id, name) VALUES ('The comic industry of Denmark, which has a lot of commonalities with the other Nordic industries.', '50855', 'Danske Tegneserier');
INSERT INTO genres (deck, id, name) VALUES ('Comics as published in Colombia.', '52146', 'Historieta Colombiana');
INSERT INTO genres (deck, id, name) VALUES ('The Eisner Awards recognize artistic excellence in the comic book industry. Created in 1987 and named after the legendary Will Eisner, the awards are presented annually at Comic-Con in San Diego.', '52148', 'Eisner Awards');
INSERT INTO genres (deck, id, name) VALUES ('Alternatively known as the Slayerverse, Whedon''s Buffyverse franchise began as a movie in 1992 (Buffy the Vampire Slayer) but came to much greater prominence when it was rebooted as a television series of the same name (1997-2003) and produced further spin-offs. One of the larger media franchises to shift over to the comic market, it published entire new "seasons" of material after the television series ended, with Whedon himself becoming a comic writer.', '55687', 'Buffyverse');
INSERT INTO genres (deck, id, name) VALUES ('Fantasy is a comic book genre often taking place in fairy tale realms.', '55701', 'Fantasy');
INSERT INTO genres (deck, id, name) VALUES ('Sport played with a ball and bat.', '55706', 'Cricket');
INSERT INTO genres (deck, id, name) VALUES ('Canon, in regards to comic books, is what is considered to be "real," "what really happened" or "what that character is really like" as opposed to events, etc., that happened in comic books, but nobody "counts it" as being "real" or "actually happened."', '55711', 'Continuity in Comics');
INSERT INTO genres (deck, id, name) VALUES ('Time travel in comics involves jumping or returning in time to change an event and therefore, altering history (alternately sometimes time travel is used simply as a means of exploration).  Heroes generally protect the time stream, villains seek to profit from its manipulation.', '55712', 'Time Travel');
