INSERT INTO genres (deck, id, name) VALUES ('A large science-fiction franchise that began with a 1994 film before branching into a sequel television series (1997-2007) and many other forms of media.', '55766', 'Stargate');
INSERT INTO genres (deck, id, name) VALUES ('Tokusatsu as a word is inherently a reference to live-action media (originally movies but often television). However its many popular franchises and new works inspired by them have crossed over into comics and this page covers broadly all its basic categories combined including kaiju, mecha and hero.', '55772', 'Tokusatsu');
INSERT INTO genres (deck, id, name) VALUES ('A look at the other side of the street.', '55776', 'Gender Change');
