INSERT INTO genres (deck, id, name) VALUES ('Most frequent in publications where comics are not the focus or where there is a mix of comic and non-comic material, these are covers where the cover itself is not advertising the comic content but is either its own piece unrelated to any interior contents or is referencing a feature in the issue other than the comics.', '55883', 'Comics-Unrelated Cover');
INSERT INTO genres (deck, id, name) VALUES ('Italian vintage comic with strong current of sex and eroticism.', '55892', 'Fumetti Erotici d''Epoca');
INSERT INTO genres (deck, id, name) VALUES ('The comic industry of Spain specifically, rather than the broader Spanish industry.', '55898', 'Historieta en España');
INSERT INTO genres (deck, id, name) VALUES (' The View Askewniverse is the name for the universe created by filmmaker Kevin Smith revolving around the characters from the New Jersey Tri-Town area. Its origins were in his 90''s films but just as Kevin Smith came to be a comic writer, the franchise has published a number of comics over the decades as well.', '55906', 'View Askewniverse');
INSERT INTO genres (deck, id, name) VALUES ('Better known as "Cosplay", Costumed Roleplaying is a custom of dressing like fictional characters.', '55907', 'Cosplay');
