INSERT INTO genres (deck, id, name) VALUES ('In December 2001, Marvel President Bill Jemas and Editor-in-Chief Joe Quesada hatched a new gimmick: for a month one issue of most of their books would feature absolutely no dialogue and rely entirely on art for the purposes of telling a story.', '56142', '''Nuff Said');